#include <stdio.h>
#include <string.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; char s[1005];
        scanf("%d", &N);
        scanf("%s", s);
        int any1 = 0, adj = 0;
        for (int i = 0; i < N; ++i) {
            if (s[i] == '1') {
                any1 = 1;
                if (i + 1 < N && s[i+1] == '1') adj = 1;
            }
        }
        int ans = any1 ? (adj ? 2 : 1) : 0;
        printf("%d\n", ans);
    }
    return 0;
}

