#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        s = next(it)
        any1 = '1' in s
        adj = '11' in s
        if not any1:
            ans = 0
        elif adj:
            ans = 2
        else:
            ans = 1
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

